import { useState, useEffect } from 'react';
import API from '../../services/axios';

const FLOWER_CSS = `
  @keyframes fadeIn { from{opacity:0;transform:translateY(16px)} to{opacity:1;transform:translateY(0)} }
`;

const StatCard = ({ icon, label, value, sub, color, trend }) => (
  <div style={{ background:'white', borderRadius:'20px', padding:'1.4rem', boxShadow:'0 4px 20px rgba(0,0,0,0.06)', border:'1px solid #f0ddd7', animation:'fadeIn 0.5s ease', position:'relative', overflow:'hidden' }}>
    <div style={{ position:'absolute', top:'-20px', right:'-20px', width:'80px', height:'80px', borderRadius:'50%', background:color, opacity:0.1 }} />
    <div style={{ display:'flex', alignItems:'flex-start', justifyContent:'space-between' }}>
      <div>
        <p style={{ color:'#a08880', fontSize:'0.76rem', fontWeight:'600', textTransform:'uppercase', margin:'0 0 6px' }}>{label}</p>
        <p style={{ color:'#2d1f1f', fontSize:'1.7rem', fontWeight:'800', margin:'0 0 4px', fontFamily:"'Cormorant Garamond',serif" }}>{value}</p>
        {sub && <p style={{ color:trend==='up'?'#2e7d52':trend==='down'?'#c0392b':'#a08880', fontSize:'0.76rem', margin:0, fontWeight:'600' }}>{trend==='up'?'▲':trend==='down'?'▼':''} {sub}</p>}
      </div>
      <div style={{ width:'46px', height:'46px', background:color, borderRadius:'14px', display:'flex', alignItems:'center', justifyContent:'center', fontSize:'1.3rem', opacity:0.85 }}>{icon}</div>
    </div>
  </div>
);

export default function AdminDashboard() {
  const [data, setData] = useState(null);
  const [loading, setLoading] = useState(true);
  const [activeTab, setActiveTab] = useState('overview');
  const [suggestions, setSuggestions] = useState([]);
  const [updatingId, setUpdatingId] = useState(null);

  useEffect(() => { fetchDashboard(); }, []);

  const fetchDashboard = async () => {
    setLoading(true);
    try {
      const [eventsRes, bookingsRes] = await Promise.all([
        API.get('/events'),
        API.get('/bookings/all/bookings'),
      ]);
      const events   = eventsRes.data?.events   || eventsRes.data   || [];
      const bookings = bookingsRes.data?.bookings || bookingsRes.data || [];

      const paidBookings      = bookings.filter(b => b.paymentStatus === 'paid' || b.status === 'confirmed');
      const totalRevenue      = paidBookings.reduce((s,b) => s+(b.totalAmount||b.totalPrice||b.amount||0),0);
      const confirmedBookings = bookings.filter(b => b.status==='confirmed');
      const cancelledBookings = bookings.filter(b => b.status==='cancelled');
      const pendingBookings   = bookings.filter(b => b.status==='pending');

      const now = new Date();
      const monthlyData = {};
      for (let i=5;i>=0;i--) {
        const d = new Date(now.getFullYear(), now.getMonth()-i, 1);
        monthlyData[d.toLocaleString('default',{month:'short',year:'2-digit'})] = 0;
      }
      paidBookings.forEach(b => {
        const key = new Date(b.createdAt||b.bookingDate).toLocaleString('default',{month:'short',year:'2-digit'});
        if (monthlyData[key]!==undefined) monthlyData[key]+=(b.totalAmount||b.totalPrice||b.amount||0);
      });

      const thisMonthKey    = now.toLocaleString('default',{month:'short',year:'2-digit'});
      const lastMonthKey    = new Date(now.getFullYear(),now.getMonth()-1,1).toLocaleString('default',{month:'short',year:'2-digit'});
      const thisMonthRev    = monthlyData[thisMonthKey]||0;
      const lastMonthRev    = monthlyData[lastMonthKey]||0;
      const momGrowth       = lastMonthRev>0?(((thisMonthRev-lastMonthRev)/lastMonthRev)*100).toFixed(1):0;

      const thisMonthCost   = thisMonthRev*0.30;
      const thisMonthProfit = thisMonthRev-thisMonthCost;
      const totalCost       = totalRevenue*0.30;
      const totalProfit     = totalRevenue-totalCost;
      const TARGET_MONTHLY  = 50000;
      const targetAchieved  = Math.min((thisMonthRev/TARGET_MONTHLY)*100,100).toFixed(0);

      const catMap={};
      events.forEach(e=>{ catMap[e.category]=(catMap[e.category]||0)+1; });

      try {
        const sugRes = await API.get('/suggestions');
        setSuggestions(sugRes.data||[]);
      } catch { setSuggestions([]); }

      setData({ events, bookings, totalRevenue, totalCost, totalProfit,
        confirmedBookings, cancelledBookings, pendingBookings,
        monthlyData, catMap, TARGET_MONTHLY,
        thisMonthRev, thisMonthCost, thisMonthProfit,
        isProfit: thisMonthProfit>=0, totalIsProfit: totalProfit>=0,
        targetAchieved, momGrowth,
        totalUsers: [...new Set(bookings.map(b=>String(b.userId||b.user)))].filter(Boolean).length,
      });
    } catch(err) { console.error(err); }
    finally { setLoading(false); }
  };

  const updateStatus = async (id, status) => {
    setUpdatingId(id);
    try {
      await API.patch(`/suggestions/${id}`, { status });
      setSuggestions(prev => prev.map(s => s._id===id ? {...s,status} : s));
    } catch { alert('Failed to update'); }
    finally { setUpdatingId(null); }
  };

  if (loading) return (
    <div style={{ display:'flex', alignItems:'center', justifyContent:'center', minHeight:'60vh', flexDirection:'column', gap:'1rem' }}>
      <div style={{ fontSize:'3rem' }}>🌸</div>
      <p style={{ color:'#a08880', fontWeight:'600' }}>Loading dashboard...</p>
    </div>
  );
  if (!data) return <div style={{ padding:'2rem', color:'#a05040' }}>❌ Failed to load.</div>;

  const maxMonthly = Math.max(...Object.values(data.monthlyData),1);
  const pendingSug = suggestions.filter(s=>s.status==='pending').length;

  return (
    <div style={{ fontFamily:"'DM Sans',sans-serif", padding:'1.5rem', background:'#fdf8f6', minHeight:'100vh' }}>
      <style>{FLOWER_CSS}</style>

      <div style={{ marginBottom:'2rem' }}>
        <h1 style={{ color:'#2d1f1f', fontWeight:'800', fontSize:'1.8rem', margin:'0 0 4px', fontFamily:"'Cormorant Garamond',serif" }}>📊 Admin Dashboard</h1>
        <p style={{ color:'#a08880', fontSize:'0.85rem', margin:0 }}>Welcome back! Here's your EventHub performance overview 🌸</p>
      </div>

      {/* Tabs */}
      <div style={{ display:'flex', gap:'8px', marginBottom:'1.5rem', flexWrap:'wrap' }}>
        {[
          {id:'overview',label:'🏠 Overview'},
          {id:'revenue', label:'💰 Revenue'},
          {id:'events',  label:'🎭 Events'},
          {id:'suggestions', label:`💡 Suggestions${pendingSug>0?` (${pendingSug})`:''}` },
        ].map(tab=>(
          <button key={tab.id} onClick={()=>setActiveTab(tab.id)}
            style={{ padding:'8px 18px', borderRadius:'20px', border:'none', cursor:'pointer', fontWeight:'600', fontSize:'0.82rem', background:activeTab===tab.id?'linear-gradient(135deg,#c9a99a,#b8887a)':'white', color:activeTab===tab.id?'white':'#a08880', boxShadow:activeTab===tab.id?'0 4px 12px rgba(201,169,154,0.4)':'0 2px 8px rgba(0,0,0,0.06)', position:'relative' }}>
            {tab.label}
            {tab.id==='suggestions' && pendingSug>0 && activeTab!=='suggestions' && (
              <span style={{ position:'absolute', top:'-6px', right:'-6px', width:'18px', height:'18px', background:'#e74c3c', borderRadius:'50%', fontSize:'0.6rem', color:'white', display:'flex', alignItems:'center', justifyContent:'center', fontWeight:'800' }}>{pendingSug}</span>
            )}
          </button>
        ))}
      </div>

      {/* ── OVERVIEW ── */}
      {activeTab==='overview' && <>
        <div style={{ display:'grid', gridTemplateColumns:'repeat(auto-fit,minmax(200px,1fr))', gap:'1rem', marginBottom:'1.5rem' }}>
          <StatCard icon="💰" label="Total Revenue"  value={`₹${data.totalRevenue.toLocaleString()}`}       sub={`${data.momGrowth>=0?'+':''}${data.momGrowth}% vs last month`} trend={data.momGrowth>=0?'up':'down'} color="#c9a99a" />
          <StatCard icon="🎫" label="Total Bookings" value={data.bookings.length}                           sub={`${data.confirmedBookings.length} confirmed`} trend="up" color="#9ab8c9" />
          <StatCard icon="🎭" label="Total Events"   value={data.events.length}                             sub={`${data.events.filter(e=>new Date(e.date)>new Date()).length} upcoming`} color="#c9b89a" />
          <StatCard icon="👥" label="Total Users"    value={data.totalUsers}                                sub="registered users" color="#b8c9a9" />
          <StatCard icon="❌" label="Cancellations"  value={data.cancelledBookings.length}                  sub={`${((data.cancelledBookings.length/Math.max(data.bookings.length,1))*100).toFixed(0)}% rate`} trend="down" color="#c9a9a9" />
          <StatCard icon="⏳" label="Pending"        value={data.pendingBookings.length}                    sub="awaiting confirmation" color="#c9c9a9" />
        </div>

        {/* THIS MONTH — 3 boxes */}
        <div style={{ display:'grid', gridTemplateColumns:'repeat(3,1fr)', gap:'1rem', marginBottom:'1.5rem' }}>
          <div style={{ background:'linear-gradient(135deg,#fdf0eb,#f5e0d8)', borderRadius:'20px', padding:'1.4rem', border:'1px solid #f0ddd7' }}>
            <p style={{ color:'#a08880', fontSize:'0.72rem', fontWeight:'700', textTransform:'uppercase', margin:'0 0 6px' }}>📅 This Month Revenue</p>
            <p style={{ color:'#2d1f1f', fontSize:'1.6rem', fontWeight:'800', margin:'0 0 4px', fontFamily:"'Cormorant Garamond',serif" }}>₹{data.thisMonthRev.toLocaleString()}</p>
            <p style={{ color:'#b8887a', fontSize:'0.75rem', margin:0, fontWeight:'600' }}>of ₹{data.TARGET_MONTHLY.toLocaleString()} target ({data.targetAchieved}%)</p>
          </div>
          <div style={{ background:data.isProfit?'linear-gradient(135deg,#edf7f0,#d4edda)':'linear-gradient(135deg,#fdeee9,#fad4cc)', borderRadius:'20px', padding:'1.4rem', border:`1px solid ${data.isProfit?'#b8ddc8':'#f0c4b8'}` }}>
            <p style={{ color:'#a08880', fontSize:'0.72rem', fontWeight:'700', textTransform:'uppercase', margin:'0 0 6px' }}>{data.isProfit?'📈 This Month Profit':'📉 This Month Loss'}</p>
            <p style={{ color:data.isProfit?'#2e7d52':'#c0392b', fontSize:'1.6rem', fontWeight:'800', margin:'0 0 4px', fontFamily:"'Cormorant Garamond',serif" }}>₹{Math.abs(Math.round(data.thisMonthProfit)).toLocaleString()}</p>
            <p style={{ color:'#a08880', fontSize:'0.75rem', margin:0, fontWeight:'600' }}>After 30% operational cost</p>
          </div>
          <div style={{ background:'linear-gradient(135deg,#fef9ec,#fdf0d8)', borderRadius:'20px', padding:'1.4rem', border:'1px solid #f0e0c8' }}>
            <p style={{ color:'#a08880', fontSize:'0.72rem', fontWeight:'700', textTransform:'uppercase', margin:'0 0 6px' }}>🏭 This Month Cost</p>
            <p style={{ color:'#8a7040', fontSize:'1.6rem', fontWeight:'800', margin:'0 0 4px', fontFamily:"'Cormorant Garamond',serif" }}>₹{Math.round(data.thisMonthCost).toLocaleString()}</p>
            <p style={{ color:'#a08880', fontSize:'0.75rem', margin:0, fontWeight:'600' }}>Operational expenses (30%)</p>
          </div>
        </div>

        {/* Monthly Target */}
        <div style={{ background:'white', borderRadius:'20px', padding:'1.5rem', boxShadow:'0 4px 20px rgba(0,0,0,0.06)', border:'1px solid #f0ddd7', marginBottom:'1.5rem' }}>
          <div style={{ display:'flex', justifyContent:'space-between', alignItems:'center', marginBottom:'1rem' }}>
            <div>
              <h3 style={{ color:'#2d1f1f', fontWeight:'700', margin:'0 0 4px', fontSize:'1rem' }}>🎯 Monthly Target</h3>
              <p style={{ color:'#a08880', fontSize:'0.8rem', margin:0 }}>₹{data.thisMonthRev.toLocaleString()} of ₹{data.TARGET_MONTHLY.toLocaleString()}</p>
            </div>
            <div style={{ textAlign:'right' }}>
              <p style={{ color:data.targetAchieved>=100?'#2e7d52':'#c9a99a', fontWeight:'800', fontSize:'1.5rem', margin:0 }}>{data.targetAchieved}%</p>
              <p style={{ color:'#a08880', fontSize:'0.75rem', margin:0 }}>{data.targetAchieved>=100?'🎉 Target Met!':'In Progress'}</p>
            </div>
          </div>
          <div style={{ height:'12px', background:'#f0ddd7', borderRadius:'6px', overflow:'hidden' }}>
            <div style={{ height:'100%', width:`${data.targetAchieved}%`, background:data.targetAchieved>=100?'linear-gradient(90deg,#2e7d52,#4caf50)':'linear-gradient(90deg,#c9a99a,#b8887a)', borderRadius:'6px', transition:'width 1s ease' }} />
          </div>
        </div>

        {/* Overall P&L */}
        <div style={{ background:data.totalIsProfit?'linear-gradient(135deg,#edf7f0,#d4edda)':'linear-gradient(135deg,#fdeee9,#fad4cc)', borderRadius:'20px', padding:'1.5rem', border:`1px solid ${data.totalIsProfit?'#b8ddc8':'#f0c4b8'}` }}>
          <div style={{ display:'flex', alignItems:'center', justifyContent:'space-between' }}>
            <div>
              <h3 style={{ color:'#2d1f1f', fontWeight:'700', margin:'0 0 10px', fontSize:'1rem' }}>{data.totalIsProfit?'📈 Overall Profit':'📉 Overall Loss'} Summary</h3>
              <div style={{ display:'flex', gap:'2rem', flexWrap:'wrap' }}>
                {[
                  {k:'GROSS REVENUE', v:`₹${data.totalRevenue.toLocaleString()}`, c:'#2d1f1f'},
                  {k:'TOTAL COST (30%)', v:`- ₹${Math.round(data.totalCost).toLocaleString()}`, c:'#c0392b'},
                  {k:`NET ${data.totalIsProfit?'PROFIT':'LOSS'}`, v:`₹${Math.abs(Math.round(data.totalProfit)).toLocaleString()}`, c:data.totalIsProfit?'#2e7d52':'#c0392b'},
                ].map(item=>(
                  <div key={item.k}>
                    <p style={{ color:'#a08880', fontSize:'0.68rem', margin:'0 0 2px', fontWeight:'700' }}>{item.k}</p>
                    <p style={{ color:item.c, fontWeight:'800', fontSize:'1rem', margin:0 }}>{item.v}</p>
                  </div>
                ))}
              </div>
            </div>
            <div style={{ fontSize:'3.5rem' }}>{data.totalIsProfit?'💹':'📉'}</div>
          </div>
        </div>
      </>}

      {/* ── REVENUE ── */}
      {activeTab==='revenue' && <>
        <div style={{ background:'white', borderRadius:'20px', padding:'1.5rem', boxShadow:'0 4px 20px rgba(0,0,0,0.06)', border:'1px solid #f0ddd7', marginBottom:'1.5rem' }}>
          <h3 style={{ color:'#2d1f1f', fontWeight:'700', marginBottom:'1.5rem', fontSize:'1rem' }}>📊 Monthly Revenue</h3>
          <div style={{ display:'flex', alignItems:'flex-end', gap:'12px', height:'180px', paddingBottom:'2rem' }}>
            {Object.entries(data.monthlyData).map(([month,rev],i,arr)=>{
              const pct=(rev/maxMonthly)*100;
              const isThis=i===arr.length-1;
              return (
                <div key={month} style={{ flex:1, display:'flex', flexDirection:'column', alignItems:'center', gap:'6px' }}>
                  <p style={{ color:'#2d1f1f', fontSize:'0.68rem', fontWeight:'700', margin:0 }}>₹{rev>999?(rev/1000).toFixed(0)+'k':rev}</p>
                  <div style={{ width:'100%', borderRadius:'8px 8px 0 0', background:isThis?'linear-gradient(180deg,#c9a99a,#b8887a)':'linear-gradient(180deg,#e8d0c8,#dcc0b5)', height:`${Math.max(pct,4)}%`, minHeight:'4px', transition:'height 0.8s ease' }} />
                  <p style={{ color:isThis?'#b8887a':'#a08880', fontSize:'0.68rem', margin:0, fontWeight:isThis?'700':'400' }}>{month}</p>
                </div>
              );
            })}
          </div>
        </div>

        <div style={{ display:'grid', gridTemplateColumns:'repeat(3,1fr)', gap:'1rem', marginBottom:'1.5rem' }}>
          {[
            {label:'📅 This Month Revenue', val:`₹${data.thisMonthRev.toLocaleString()}`,            color:'#b8887a', bg:'#fdf0eb'},
            {label:data.isProfit?'📈 This Month Profit':'📉 This Month Loss', val:`₹${Math.round(Math.abs(data.thisMonthProfit)).toLocaleString()}`, color:data.isProfit?'#2e7d52':'#c0392b', bg:data.isProfit?'#edf7f0':'#fdeee9'},
            {label:'🏭 This Month Cost',    val:`₹${Math.round(data.thisMonthCost).toLocaleString()}`, color:'#8a7040', bg:'#fef9ec'},
          ].map((item,i)=>(
            <div key={i} style={{ background:item.bg, borderRadius:'16px', padding:'1.2rem', border:'1px solid #f0ddd7', textAlign:'center' }}>
              <p style={{ color:'#a08880', fontSize:'0.73rem', fontWeight:'700', margin:'0 0 6px' }}>{item.label}</p>
              <p style={{ color:item.color, fontSize:'1.4rem', fontWeight:'800', margin:0, fontFamily:"'Cormorant Garamond',serif" }}>{item.val}</p>
            </div>
          ))}
        </div>

        <div style={{ display:'grid', gridTemplateColumns:'1fr 1fr', gap:'1rem' }}>
          <div style={{ background:'white', borderRadius:'20px', padding:'1.5rem', boxShadow:'0 4px 20px rgba(0,0,0,0.06)', border:'1px solid #f0ddd7' }}>
            <h3 style={{ color:'#2d1f1f', fontWeight:'700', marginBottom:'1rem', fontSize:'0.95rem' }}>💰 Overall Breakdown</h3>
            {[
              {label:'Gross Revenue',     val:`₹${data.totalRevenue.toLocaleString()}`,                   color:'#2e7d52'},
              {label:'Operational (30%)', val:`₹${Math.round(data.totalCost).toLocaleString()}`,           color:'#c0392b'},
              {label:data.totalIsProfit?'Net Profit ✅':'Net Loss ❌', val:`₹${Math.abs(Math.round(data.totalProfit)).toLocaleString()}`, color:data.totalIsProfit?'#2e7d52':'#c0392b'},
            ].map((item,i)=>(
              <div key={i} style={{ display:'flex', justifyContent:'space-between', padding:'10px 0', borderBottom:i<2?'1px solid #f0ddd7':'none' }}>
                <span style={{ color:'#6b5a55', fontSize:'0.84rem' }}>{item.label}</span>
                <span style={{ color:item.color, fontWeight:'700', fontSize:'0.88rem' }}>{item.val}</span>
              </div>
            ))}
          </div>
          <div style={{ background:'white', borderRadius:'20px', padding:'1.5rem', boxShadow:'0 4px 20px rgba(0,0,0,0.06)', border:'1px solid #f0ddd7' }}>
            <h3 style={{ color:'#2d1f1f', fontWeight:'700', marginBottom:'1rem', fontSize:'0.95rem' }}>🎯 Target Analysis</h3>
            {[
              {label:'Monthly Target',    val:`₹${data.TARGET_MONTHLY.toLocaleString()}`},
              {label:'This Month Earned', val:`₹${data.thisMonthRev.toLocaleString()}`},
              {label:'Achievement',       val:`${data.targetAchieved}%`, color:data.targetAchieved>=100?'#2e7d52':'#c9a99a'},
              {label:'Remaining',         val:`₹${Math.max(0,data.TARGET_MONTHLY-data.thisMonthRev).toLocaleString()}`, color:'#c0392b'},
              {label:'MoM Growth',        val:`${data.momGrowth>=0?'+':''}${data.momGrowth}%`, color:data.momGrowth>=0?'#2e7d52':'#c0392b'},
            ].map((item,i)=>(
              <div key={i} style={{ display:'flex', justifyContent:'space-between', padding:'8px 0', borderBottom:i<4?'1px solid #f0ddd7':'none' }}>
                <span style={{ color:'#6b5a55', fontSize:'0.82rem' }}>{item.label}</span>
                <span style={{ color:item.color||'#2d1f1f', fontWeight:'700', fontSize:'0.84rem' }}>{item.val}</span>
              </div>
            ))}
          </div>
        </div>
      </>}

      {/* ── EVENTS ── */}
      {activeTab==='events' && <>
        <div style={{ background:'white', borderRadius:'20px', padding:'1.5rem', boxShadow:'0 4px 20px rgba(0,0,0,0.06)', border:'1px solid #f0ddd7', marginBottom:'1.5rem' }}>
          <h3 style={{ color:'#2d1f1f', fontWeight:'700', marginBottom:'1.2rem', fontSize:'1rem' }}>🎭 Events by Category</h3>
          {Object.entries(data.catMap).map(([cat,count])=>{
            const pct=(count/data.events.length)*100;
            return (
              <div key={cat} style={{ marginBottom:'10px' }}>
                <div style={{ display:'flex', justifyContent:'space-between', marginBottom:'4px' }}>
                  <span style={{ color:'#6b5a55', fontSize:'0.82rem', fontWeight:'600' }}>{cat}</span>
                  <span style={{ color:'#a08880', fontSize:'0.8rem' }}>{count} ({pct.toFixed(0)}%)</span>
                </div>
                <div style={{ height:'8px', background:'#f0ddd7', borderRadius:'4px', overflow:'hidden' }}>
                  <div style={{ height:'100%', width:`${pct}%`, background:'linear-gradient(90deg,#c9a99a,#b8887a)', borderRadius:'4px', transition:'width 0.8s ease' }} />
                </div>
              </div>
            );
          })}
        </div>
        <div style={{ background:'white', borderRadius:'20px', padding:'1.5rem', boxShadow:'0 4px 20px rgba(0,0,0,0.06)', border:'1px solid #f0ddd7' }}>
          <h3 style={{ color:'#2d1f1f', fontWeight:'700', marginBottom:'1.2rem', fontSize:'1rem' }}>🏆 All Events</h3>
          <div style={{ display:'flex', flexDirection:'column', gap:'10px', maxHeight:'400px', overflowY:'auto' }}>
            {data.events.map((event,i)=>(
              <div key={i} style={{ display:'flex', alignItems:'center', gap:'12px', padding:'12px', background:'#fdf8f6', borderRadius:'14px', border:'1px solid #f0ddd7' }}>
                <div style={{ width:'42px', height:'42px', background:'linear-gradient(135deg,#c9a99a,#b8887a)', borderRadius:'12px', display:'flex', alignItems:'center', justifyContent:'center', color:'white', fontWeight:'700', fontSize:'0.9rem', flexShrink:0 }}>{i+1}</div>
                <div style={{ flex:1 }}>
                  <p style={{ color:'#2d1f1f', fontWeight:'600', margin:'0 0 2px', fontSize:'0.88rem' }}>{event.name}</p>
                  <p style={{ color:'#a08880', fontSize:'0.76rem', margin:0 }}>{event.category} • {new Date(event.date).toDateString()} • ₹{event.price}</p>
                </div>
                <span style={{ padding:'4px 10px', borderRadius:'20px', fontSize:'0.72rem', fontWeight:'700', background:new Date(event.date)>new Date()?'#edf7f0':'#fdeee9', color:new Date(event.date)>new Date()?'#2e7d52':'#c0392b' }}>{new Date(event.date)>new Date()?'Upcoming':'Past'}</span>
              </div>
            ))}
          </div>
        </div>
      </>}

      {/* ── SUGGESTIONS ── */}
      {activeTab==='suggestions' && (
        <div>
          <div style={{ display:'flex', justifyContent:'space-between', alignItems:'center', marginBottom:'1rem', flexWrap:'wrap', gap:'8px' }}>
            <h3 style={{ color:'#2d1f1f', fontWeight:'700', fontSize:'1rem', margin:0 }}>💡 Audience Event Suggestions</h3>
            <div style={{ display:'flex', gap:'6px' }}>
              {[
                {label:'All',      count:suggestions.length,                                   color:'#a08880'},
                {label:'Pending',  count:suggestions.filter(s=>s.status==='pending').length,   color:'#8a7040'},
                {label:'Approved', count:suggestions.filter(s=>s.status==='approved').length,  color:'#2e7d52'},
                {label:'Rejected', count:suggestions.filter(s=>s.status==='rejected').length,  color:'#c0392b'},
              ].map(item=>(
                <span key={item.label} style={{ padding:'4px 10px', borderRadius:'20px', background:'#fdf0eb', color:item.color, fontSize:'0.72rem', fontWeight:'700' }}>{item.label}: {item.count}</span>
              ))}
            </div>
          </div>

          <div style={{ background:'white', borderRadius:'20px', padding:'1.5rem', boxShadow:'0 4px 20px rgba(0,0,0,0.06)', border:'1px solid #f0ddd7' }}>
            {suggestions.length===0 ? (
              <div style={{ textAlign:'center', padding:'3rem', color:'#a08880' }}>
                <div style={{ fontSize:'3rem', marginBottom:'1rem' }}>💡</div>
                <p style={{ fontWeight:'600', fontSize:'1rem' }}>No suggestions yet!</p>
                <p style={{ fontSize:'0.84rem' }}>When users submit event ideas, they'll appear here.</p>
              </div>
            ) : (
              <div style={{ display:'flex', flexDirection:'column', gap:'14px' }}>
                {suggestions.map(s=>(
                  <div key={s._id} style={{ padding:'1.3rem', background:'#fdf8f6', borderRadius:'16px', border:`1px solid ${s.status==='approved'?'#b8ddc8':s.status==='rejected'?'#f0c4b8':'#f0ddd7'}`, animation:'fadeIn 0.4s ease' }}>
                    <div style={{ display:'flex', justifyContent:'space-between', alignItems:'flex-start', marginBottom:'8px', flexWrap:'wrap', gap:'8px' }}>
                      <div>
                        <h4 style={{ color:'#2d1f1f', fontWeight:'700', margin:'0 0 6px', fontSize:'0.95rem' }}>{s.title}</h4>
                        <div style={{ display:'flex', gap:'6px', flexWrap:'wrap' }}>
                          <span style={{ background:'#fdf0eb', color:'#b8887a', padding:'3px 10px', borderRadius:'20px', fontSize:'0.7rem', fontWeight:'600' }}>{s.category}</span>
                          <span style={{ padding:'3px 10px', borderRadius:'20px', fontSize:'0.7rem', fontWeight:'700', background:s.status==='approved'?'#edf7f0':s.status==='rejected'?'#fdeee9':'#fef9ec', color:s.status==='approved'?'#2e7d52':s.status==='rejected'?'#c0392b':'#8a7040' }}>{s.status?.toUpperCase()}</span>
                        </div>
                      </div>
                      <span style={{ color:'#a08880', fontSize:'0.74rem' }}>{new Date(s.createdAt).toLocaleDateString('en-IN')}</span>
                    </div>
                    <p style={{ color:'#6b5a55', fontSize:'0.83rem', margin:'8px 0', lineHeight:'1.6' }}>{s.description}</p>
                    <div style={{ display:'flex', gap:'1rem', flexWrap:'wrap', marginBottom:'12px' }}>
                      {s.expectedVenue    && <span style={{ color:'#a08880', fontSize:'0.76rem' }}>📍 {s.expectedVenue}</span>}
                      {s.expectedDate     && <span style={{ color:'#a08880', fontSize:'0.76rem' }}>📅 {new Date(s.expectedDate).toDateString()}</span>}
                      {s.expectedAudience && <span style={{ color:'#a08880', fontSize:'0.76rem' }}>👥 {s.expectedAudience}</span>}
                      {s.contactEmail     && <span style={{ color:'#a08880', fontSize:'0.76rem' }}>📧 {s.contactEmail}</span>}
                    </div>
                    {s.status==='pending' && (
                      <div style={{ display:'flex', gap:'8px' }}>
                        <button onClick={()=>updateStatus(s._id,'approved')} disabled={updatingId===s._id}
                          style={{ padding:'7px 16px', background:'linear-gradient(135deg,#4caf50,#2e7d52)', color:'white', border:'none', borderRadius:'10px', cursor:'pointer', fontWeight:'600', fontSize:'0.78rem', fontFamily:"'DM Sans',sans-serif", opacity:updatingId===s._id?0.6:1 }}>
                          ✅ Approve
                        </button>
                        <button onClick={()=>updateStatus(s._id,'rejected')} disabled={updatingId===s._id}
                          style={{ padding:'7px 16px', background:'#fdeee9', color:'#c0392b', border:'1px solid #f0c4b8', borderRadius:'10px', cursor:'pointer', fontWeight:'600', fontSize:'0.78rem', fontFamily:"'DM Sans',sans-serif" }}>
                          ❌ Reject
                        </button>
                      </div>
                    )}
                    {s.status!=='pending' && (
                      <button onClick={()=>updateStatus(s._id,'pending')}
                        style={{ padding:'6px 14px', background:'white', color:'#a08880', border:'1px solid #f0ddd7', borderRadius:'10px', cursor:'pointer', fontWeight:'600', fontSize:'0.75rem', fontFamily:"'DM Sans',sans-serif" }}>
                        🔄 Reset to Pending
                      </button>
                    )}
                  </div>
                ))}
              </div>
            )}
          </div>
        </div>
      )}
    </div>
  );
}
